const { app } = require('@azure/functions');
const { CosmosClient } = require('@azure/cosmos');

const cosmosClient = new CosmosClient({
    endpoint: process.env.COSMOS_DB_ENDPOINT,
    key: process.env.COSMOS_DB_KEY
});

const database = cosmosClient.database(process.env.COSMOS_DB_DATABASE);
const container = database.container(process.env.COSMOS_DB_CONTAINER);

async function processBatch(items) {
    const results = [];
    for (const item of items) {
        try {
            const processed = {
                ...item,
                processed: true,
                processedAt: new Date().toISOString(),
                computedValue: performComplexCalculation(item)
            };
            results.push(processed);
        } catch (error) {
            results.push({
                ...item,
                error: error.message,
                processedAt: new Date().toISOString()
            });
        }
    }
    return results;
}

function performComplexCalculation(item) {
    let result = 0;
    if (item.data && Array.isArray(item.data)) {
        result = item.data.reduce((sum, val) => sum + (val || 0), 0);
    }
    return result;
}

async function updateCosmosDB(processedItems) {
    const operations = processedItems.map(item => ({
        operationType: 'Replace',
        id: item.id,
        resourceBody: item,
        partitionKey: item.partitionKey || item.id
    }));

    const batchSize = 100;
    for (let i = 0; i < operations.length; i += batchSize) {
        const batch = operations.slice(i, i + batchSize);
        for (const op of batch) {
            try {
                await container.item(op.id, op.partitionKey).replace(op.resourceBody);
            } catch (error) {
                console.error(`Failed to update item ${op.id}:`, error.message);
            }
        }
    }
}

async function getAllItems(query) {
    const items = [];
    const querySpec = {
        query: query || "SELECT * FROM c WHERE NOT IS_DEFINED(c.processed) OR c.processed = false"
    };

    const { resources } = await container.items.query(querySpec, {
        maxItemCount: -1
    }).fetchAll();

    return resources;
}

app.http('batchDataProcessor', {
    methods: ['GET', 'POST'],
    authLevel: 'function',
    timeout: '00:10:00',
    handler: async (request, context) => {
        const startTime = Date.now();
        context.log('Batch processing started at:', new Date().toISOString());

        try {
            const query = request.query.get('query') || (await request.text());
            
            context.log('Fetching items from Cosmos DB...');
            const items = await getAllItems(query);
            context.log(`Retrieved ${items.length} items for processing`);

            if (items.length === 0) {
                return {
                    status: 200,
                    body: JSON.stringify({
                        success: true,
                        message: 'No items to process',
                        itemsProcessed: 0,
                        duration: Date.now() - startTime
                    })
                };
            }

            const batchSize = 500;
            let totalProcessed = 0;
            const results = [];

            for (let i = 0; i < items.length; i += batchSize) {
                const elapsedTime = (Date.now() - startTime) / 1000;
                
                if (elapsedTime > 570) {
                    context.log('Approaching timeout limit, stopping processing');
                    break;
                }

                const batch = items.slice(i, i + batchSize);
                context.log(`Processing batch ${Math.floor(i / batchSize) + 1}, items ${i + 1} to ${Math.min(i + batchSize, items.length)}`);

                const processedBatch = await processBatch(batch);
                results.push(...processedBatch);

                context.log('Updating Cosmos DB with processed items...');
                await updateCosmosDB(processedBatch);

                totalProcessed += processedBatch.length;
                context.log(`Processed ${totalProcessed} items so far`);
            }

            const duration = Date.now() - startTime;
            const summary = {
                success: true,
                itemsProcessed: totalProcessed,
                totalItems: items.length,
                duration: duration,
                durationSeconds: Math.round(duration / 1000),
                completedAt: new Date().toISOString()
            };

            context.log('Batch processing completed:', summary);

            return {
                status: 200,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(summary)
            };

        } catch (error) {
            context.log.error('Error during batch processing:', error);
            
            return {
                status: 500,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    success: false,
                    error: error.message,
                    stack: error.stack,
                    duration: Date.now() - startTime
                })
            };
        }
    }
});

app.timer('scheduledBatchProcessor', {
    schedule: '0 0 */6 * * *',
    timeout: '00:10:00',
    handler: async (myTimer, context) => {
        const startTime = Date.now();
        context.log('Scheduled batch processing triggered at:', new Date().toISOString());

        try {
            context.log('Fetching unprocessed items...');
            const items = await getAllItems();
            context.log(`Retrieved ${items.length} unprocessed items`);

            if (items.length === 0) {
                context.log('No items to process');
                return;
            }

            const batchSize = 500;
            let totalProcessed = 0;

            for (let i = 0; i < items.length; i += batchSize) {
                const elapsedTime = (Date.now() - startTime) / 1000;
                
                if (elapsedTime > 570) {
                    context.log('Approaching timeout, stopping processing');
                    break;
                }

                const batch = items.slice(i, i + batchSize);
                context.log(`Processing batch ${Math.floor(i / batchSize) + 1}`);

                const processedBatch = await processBatch(batch);
                await updateCosmosDB(processedBatch);

                totalProcessed += processedBatch.length;
                context.log(`Progress: ${totalProcessed}/${items.length} items processed`);
            }

            const duration = Date.now() - startTime;
            context.log(`Scheduled processing completed. Processed ${totalProcessed} items in ${Math.round(duration / 1000)} seconds`);

        } catch (error) {
            context.log.error('Error in scheduled batch processing:', error);
            throw error;
        }
    }
});

app.http('continuationProcessor', {
    methods: ['POST'],
    authLevel: 'function',
    timeout: '00:10:00',
    handler: async (request, context) => {
        const startTime = Date.now();
        context.log('Continuation processing started');

        try {
            const requestBody = await request.json();
            const continuationToken = requestBody.continuationToken;
            const batchSize = requestBody.batchSize || 1000;

            const queryIterator = container.items.query(
                "SELECT * FROM c WHERE NOT IS_DEFINED(c.processed) OR c.processed = false",
                {
                    maxItemCount: batchSize,
                    continuationToken: continuationToken
                }
            );

            const { resources: items, continuationToken: nextToken } = await queryIterator.fetchNext();
            
            context.log(`Retrieved ${items.length} items with continuation`);

            if (items.length > 0) {
                const processedItems = await processBatch(items);
                await updateCosmosDB(processedItems);
            }

            return {
                status: 200,
                body: JSON.stringify({
                    success: true,
                    itemsProcessed: items.length,
                    continuationToken: nextToken,
                    hasMore: !!nextToken,
                    duration: Date.now() - startTime
                })
            };

        } catch (error) {
            context.log.error('Error in continuation processing:', error);
            return {
                status: 500,
                body: JSON.stringify({
                    success: false,
                    error: error.message
                })
            };
        }
    }
});